using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // ──────────────────────────────────────────────
    // CalculateTotal – DataRow (inline values)
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price with 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(10.00, 0, 0.10, 0.00, DisplayName = "Zero quantity")]
    [DataRow(99.99, 1, 1.0, 199.98, DisplayName = "100% tax rate")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        // Arrange — DataRow doesn't support decimal literals, so convert from double
        var unitPriceDec = (decimal)unitPrice;
        var taxRateDec = (decimal)taxRate;
        var expectedDec = (decimal)expected;

        // Act
        var result = _calculator.CalculateTotal(unitPriceDec, quantity, taxRateDec);

        // Assert
        Assert.AreEqual(expectedDec, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative unit price")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity")]
    public void CalculateTotal_WithNegativeInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_WithInvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // ──────────────────────────────────────────────
    // ApplyDiscount – DynamicData with ValueTuples
    // ──────────────────────────────────────────────

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 0m, 100m),       // No discount
        (100m, 10m, 90m),       // 10% off
        (100m, 25m, 75m),       // 25% off
        (100m, 50m, 50m),       // Half price
        (100m, 100m, 0m),       // Full discount
        (200m, 15m, 170m),      // 15% off higher price
        (0m, 50m, 0m),          // Zero price
        (49.99m, 20m, 39.992m), // Fractional result
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountData))]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    public static IEnumerable<(decimal price, decimal discountPercent)> InvalidDiscountData =>
    [
        (100m, -1m),   // Below zero
        (100m, 101m),  // Above 100
        (100m, -0.01m),
        (100m, 100.01m),
    ];

    // ──────────────────────────────────────────────
    // FormatPrice – DataRow for string verification
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, "$", "$10.00")]
    [DataRow(0.00, "$", "$0.00")]
    [DataRow(99.999, "€", "€100.00")]
    [DataRow(1234.50, "£", "£1234.50")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_WithDefaultCurrency_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.50m);

        Assert.StartsWith("$", result);
        Assert.AreEqual("$42.50", result);
    }
}

